import React, { useState, useEffect, useRef } from 'react';
import { useHistory } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import '../styles/AdminSidebar.css';

// Ant Design imports
import {
  Layout, Menu, Card, Table, Button, Form, Input, Upload, Modal, Select,
  Tabs, Progress, notification, Tag, Space, Divider, Row, Col, Statistic,
  DatePicker, Switch, InputNumber, Spin, Alert, Typography, Rate,
  Drawer, Breadcrumb, Empty, List, Timeline, Tooltip, Avatar, Badge,
  Popconfirm, message, Descriptions, Steps, Collapse, Dropdown, Slider,
  Checkbox, Radio, AutoComplete, Cascader, TimePicker, Transfer, TreeSelect
} from 'antd';

import {
  PlusOutlined, EditOutlined, DeleteOutlined, UploadOutlined,
  DownloadOutlined, FileOutlined, VideoCameraOutlined, AudioOutlined,
  QuestionCircleOutlined, CheckCircleOutlined, CloseCircleOutlined,
  EyeOutlined, SearchOutlined, FilterOutlined, BookOutlined,
  FileTextOutlined, PlayCircleOutlined, HomeOutlined, UserOutlined,
  BarChartOutlined, CalendarOutlined, BellOutlined, SettingOutlined,
  MenuFoldOutlined, MenuUnfoldOutlined, StarOutlined, ClockCircleOutlined,
  TrophyOutlined, MessageOutlined, TeamOutlined, DashboardOutlined,
  SolutionOutlined, FundOutlined, PieChartOutlined, LineChartOutlined,
  AreaChartOutlined, RadarChartOutlined, HeatMapOutlined, DotChartOutlined,
  GlobalOutlined, MailOutlined, PhoneOutlined, EnvironmentOutlined,
  SafetyOutlined, LockOutlined, KeyOutlined, CloudOutlined, DatabaseOutlined,
  ApiOutlined, CodeOutlined, BugOutlined, ToolOutlined, ExperimentOutlined,
  RocketOutlined, ThunderboltOutlined, FireOutlined, GiftOutlined,
  HeartOutlined, SmileOutlined, FrownOutlined, MehOutlined,
  LikeOutlined, DislikeOutlined, CommentOutlined, ShareAltOutlined,
  SaveOutlined, PrinterOutlined, ScanOutlined, WifiOutlined,
  SoundOutlined, NotificationOutlined, WarningOutlined, InfoCircleOutlined,
  ExclamationCircleOutlined, StopOutlined, PauseCircleOutlined,
  ForwardOutlined, BackwardOutlined, FastForwardOutlined, FastBackwardOutlined,
  StepForwardOutlined, StepBackwardOutlined, CaretRightOutlined,
  CaretLeftOutlined, CaretUpOutlined, CaretDownOutlined,
  FullscreenOutlined, FullscreenExitOutlined, ExpandOutlined,
  CompressOutlined, PlusCircleOutlined, MinusCircleOutlined,
  CheckSquareOutlined, BorderOutlined, FormOutlined, HighlightOutlined,
  SnippetsOutlined, DiffOutlined, CopyOutlined, ScissorOutlined,
  DeleteRowOutlined, MergeCellsOutlined, SplitCellsOutlined,
  AppstoreOutlined, BarsOutlined, BuildOutlined, BlockOutlined,
  GatewayOutlined, ClusterOutlined, DeploymentUnitOutlined,
  VerifiedOutlined, SafetyCertificateOutlined, SecurityScanOutlined,
  IdcardOutlined, ContactsOutlined, FolderOutlined, FolderOpenOutlined,
  FolderAddOutlined, HddOutlined, CloudServerOutlined, CloudSyncOutlined,
  CloudDownloadOutlined, CloudUploadOutlined, InboxOutlined, LaptopOutlined,
  MobileOutlined, TabletOutlined, DesktopOutlined, WalletOutlined,
  BankOutlined, CreditCardOutlined, DollarOutlined, EuroOutlined,
  PoundOutlined, TransactionOutlined, MoneyCollectOutlined,
  FieldTimeOutlined, HistoryOutlined, ReloadOutlined, SyncOutlined,
  RedoOutlined, UndoOutlined, LoginOutlined, LogoutOutlined,
  UserAddOutlined, UserDeleteOutlined, UsergroupAddOutlined,
  UsergroupDeleteOutlined, ManOutlined, WomanOutlined,
  ShoppingCartOutlined, ShoppingOutlined, ShopOutlined,
  TagsOutlined, BarcodeOutlined, QrcodeOutlined,
  CameraOutlined, PictureOutlined, CompassOutlined,
  AimOutlined, SendOutlined, RiseOutlined,
  FallOutlined, StockOutlined, FundProjectionScreenOutlined,
  SlackOutlined, SkypeOutlined, LinkedinOutlined, TwitterOutlined,
  FacebookOutlined, YoutubeOutlined, InstagramOutlined, GithubOutlined,
  GitlabOutlined, DribbbleOutlined, BehanceOutlined, CodepenOutlined
} from '@ant-design/icons';

import moment from 'moment';
import { Line, Bar, Doughnut, Radar, Pie } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  RadialLinearScale,
  Title as ChartTitle,
  Tooltip as ChartTooltip,
  Legend,
  Filler
} from 'chart.js';

// Register Chart.js components
ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  RadialLinearScale,
  ChartTitle,
  ChartTooltip,
  Legend,
  Filler
);

// Import API clients
import { authAPI, statsAPI, courseAPI, materialAPI, quizAPI, homeworkAPI, userAPI } from '../utils/apiClient';

const { Header, Sider, Content } = Layout;
const { Title, Text, Paragraph } = Typography;
const { TabPane } = Tabs;
const { Option } = Select;
const { TextArea } = Input;
const { Dragger } = Upload;
const { RangePicker } = DatePicker;
const { Panel } = Collapse;
const { Step } = Steps;
const { Meta } = Card;
const { SubMenu } = Menu;
const { confirm } = Modal;

// Main Dashboard Component
const AdminFacultyDashboard = () => {
  const { t } = useTranslation();
  const history = useHistory();
  
  // States
  const [collapsed, setCollapsed] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeKey, setActiveKey] = useState('overview');
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  const [theme, setTheme] = useState('dark');
  
  // Dashboard data states
  const [dashboardStats, setDashboardStats] = useState({
    totalCourses: 0,
    totalStudents: 0,
    totalMaterials: 0,
    pendingSubmissions: 0,
    activeQuizzes: 0,
    completionRate: 0,
    totalTeachers: 0,
    totalRevenue: 0,
    newApplications: 0,
    upcomingEvents: 0
  });

  // Component-specific states
  const [courses, setCourses] = useState([]);
  const [materials, setMaterials] = useState([]);
  const [quizzes, setQuizzes] = useState([]);
  const [homework, setHomework] = useState([]);
  const [students, setStudents] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [applications, setApplications] = useState([]);
  const [contactMessages, setContactMessages] = useState([]);
  const [listeningExercises, setListeningExercises] = useState([]);
  const [analyticsData, setAnalyticsData] = useState({});
  
  // Forms
  const [courseForm] = Form.useForm();
  const [materialForm] = Form.useForm();
  const [quizForm] = Form.useForm();
  const [homeworkForm] = Form.useForm();
  
  // Modals
  const [courseModalVisible, setCourseModalVisible] = useState(false);
  const [materialModalVisible, setMaterialModalVisible] = useState(false);
  const [quizModalVisible, setQuizModalVisible] = useState(false);
  const [homeworkModalVisible, setHomeworkModalVisible] = useState(false);
  
  // Refs for audio players
  const audioRef = useRef(null);

  // Responsive handler
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768);
      if (window.innerWidth < 768) {
        setCollapsed(true);
      }
    };
    
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Authentication check
  useEffect(() => {
    const checkAuth = () => {
      const token = localStorage.getItem('authToken') || localStorage.getItem('token');
      const userRole = localStorage.getItem('userRole');
      const userEmail = localStorage.getItem('userEmail');
      const userName = localStorage.getItem('userName');
      const userId = localStorage.getItem('userId');
      
      if (!token || !userRole) {
        history.push('/login');
        return;
      }

      if (!['superadmin', 'admin', 'faculty', 'teacher'].includes(userRole)) {
        message.error('Access denied. Admin/Faculty role required.');
        history.push('/');
        return;
      }
      
      const userData = {
        id: userId,
        email: userEmail,
        role: userRole,
        name: userName,
        firstName: userName?.split(' ')[0] || 'Admin',
        lastName: userName?.split(' ')[1] || 'User'
      };
      
      setCurrentUser(userData);
      fetchInitialData();
      setLoading(false);
    };

    checkAuth();
  }, [history]);

  // Fetch initial data
  const fetchInitialData = async () => {
    try {
      await Promise.all([
        fetchDashboardStats(),
        fetchCourses(),
        fetchStudents(),
        fetchApplications()
      ]);
    } catch (error) {
      console.error('Error fetching initial data:', error);
    }
  };

  const fetchDashboardStats = async () => {
    try {
      const stats = await statsAPI.getDashboardStats();
      setDashboardStats(stats);
    } catch (error) {
      console.error('Error fetching dashboard stats:', error);
    }
  };

  const fetchCourses = async () => {
    try {
      const data = await courseAPI.getAll();
      setCourses(data);
    } catch (error) {
      console.error('Error fetching courses:', error);
    }
  };

  const fetchStudents = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('/api/users?role=student', {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });
      if (response.ok) {
        const data = await response.json();
        setStudents(data);
      }
    } catch (error) {
      console.error('Error fetching students:', error);
    }
  };

  const fetchApplications = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('/api/applications', {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });
      if (response.ok) {
        const data = await response.json();
        setApplications(data.applications || data);
      }
    } catch (error) {
      console.error('Error fetching applications:', error);
    }
  };

  const handleLogout = () => {
    confirm({
      title: 'Confirm Logout',
      content: 'Are you sure you want to logout?',
      okText: 'Yes',
      cancelText: 'No',
      onOk() {
        localStorage.clear();
        message.success('Logged out successfully');
        history.push('/');
      }
    });
  };

  // Menu items with icons
  const menuItems = [
    {
      key: 'overview',
      icon: <DashboardOutlined />,
      label: 'Dashboard Overview'
    },
    {
      key: 'courses',
      icon: <BookOutlined />,
      label: 'Course Management'
    },
    {
      key: 'materials',
      icon: <FolderOutlined />,
      label: 'Course Materials'
    },
    {
      key: 'quizzes',
      icon: <FormOutlined />,
      label: 'Quiz Engine'
    },
    {
      key: 'homework',
      icon: <FileTextOutlined />,
      label: 'Homework System'
    },
    {
      key: 'listening',
      icon: <AudioOutlined />,
      label: 'Listening Exercises'
    },
    {
      key: 'students',
      icon: <TeamOutlined />,
      label: 'Student Progress'
    },
    {
      key: 'applications',
      icon: <SolutionOutlined />,
      label: 'Applications'
    },
    {
      key: 'analytics',
      icon: <BarChartOutlined />,
      label: 'Analytics & Reports'
    },
    {
      key: 'settings',
      icon: <SettingOutlined />,
      label: 'Settings'
    }
  ];

  // Render Dashboard Overview
  const renderOverview = () => (
    <div className="dashboard-overview">
      <Row gutter={[24, 24]}>
        {/* Stats Cards */}
        <Col xs={24} sm={12} lg={6}>
          <Card className="stat-card gradient-blue" hoverable>
            <Statistic
              title={<span style={{ color: '#fff' }}>Total Courses</span>}
              value={dashboardStats.totalCourses}
              prefix={<BookOutlined style={{ color: '#fff' }} />}
              valueStyle={{ color: '#fff', fontSize: '32px' }}
            />
            <Progress 
              percent={75} 
              strokeColor="#fff" 
              trailColor="rgba(255,255,255,0.3)"
              showInfo={false}
              style={{ marginTop: 10 }}
            />
          </Card>
        </Col>
        
        <Col xs={24} sm={12} lg={6}>
          <Card className="stat-card gradient-green" hoverable>
            <Statistic
              title={<span style={{ color: '#fff' }}>Total Students</span>}
              value={dashboardStats.totalStudents}
              prefix={<UserOutlined style={{ color: '#fff' }} />}
              valueStyle={{ color: '#fff', fontSize: '32px' }}
            />
            <Progress 
              percent={85} 
              strokeColor="#fff" 
              trailColor="rgba(255,255,255,0.3)"
              showInfo={false}
              style={{ marginTop: 10 }}
            />
          </Card>
        </Col>
        
        <Col xs={24} sm={12} lg={6}>
          <Card className="stat-card gradient-orange" hoverable>
            <Statistic
              title={<span style={{ color: '#fff' }}>Course Materials</span>}
              value={dashboardStats.totalMaterials}
              prefix={<FileOutlined style={{ color: '#fff' }} />}
              valueStyle={{ color: '#fff', fontSize: '32px' }}
            />
            <Progress 
              percent={60} 
              strokeColor="#fff" 
              trailColor="rgba(255,255,255,0.3)"
              showInfo={false}
              style={{ marginTop: 10 }}
            />
          </Card>
        </Col>
        
        <Col xs={24} sm={12} lg={6}>
          <Card className="stat-card gradient-purple" hoverable>
            <Statistic
              title={<span style={{ color: '#fff' }}>Pending Reviews</span>}
              value={dashboardStats.pendingSubmissions}
              prefix={<ClockCircleOutlined style={{ color: '#fff' }} />}
              valueStyle={{ color: '#fff', fontSize: '32px' }}
            />
            <Progress 
              percent={30} 
              strokeColor="#fff" 
              trailColor="rgba(255,255,255,0.3)"
              showInfo={false}
              style={{ marginTop: 10 }}
            />
          </Card>
        </Col>
      </Row>

      {/* Charts Row */}
      <Row gutter={[24, 24]} style={{ marginTop: 24 }}>
        <Col xs={24} lg={16}>
          <Card 
            title="Student Performance Trends" 
            extra={
              <Select defaultValue="week" style={{ width: 120 }}>
                <Option value="week">This Week</Option>
                <Option value="month">This Month</Option>
                <Option value="year">This Year</Option>
              </Select>
            }
          >
            <Line
              data={{
                labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
                datasets: [
                  {
                    label: 'Average Score',
                    data: [75, 78, 80, 82, 79, 85, 88],
                    borderColor: '#1890ff',
                    backgroundColor: 'rgba(24, 144, 255, 0.1)',
                    tension: 0.4
                  },
                  {
                    label: 'Completion Rate',
                    data: [65, 70, 72, 75, 73, 78, 82],
                    borderColor: '#52c41a',
                    backgroundColor: 'rgba(82, 196, 26, 0.1)',
                    tension: 0.4
                  }
                ]
              }}
              options={{
                responsive: true,
                plugins: {
                  legend: {
                    position: 'top'
                  }
                },
                scales: {
                  y: {
                    beginAtZero: true,
                    max: 100
                  }
                }
              }}
            />
          </Card>
        </Col>
        
        <Col xs={24} lg={8}>
          <Card title="Course Distribution">
            <Doughnut
              data={{
                labels: ['Language', 'Business', 'Technology', 'Arts', 'Science'],
                datasets: [{
                  data: [30, 25, 20, 15, 10],
                  backgroundColor: [
                    '#1890ff',
                    '#52c41a',
                    '#faad14',
                    '#f5222d',
                    '#722ed1'
                  ]
                }]
              }}
              options={{
                responsive: true,
                plugins: {
                  legend: {
                    position: 'bottom'
                  }
                }
              }}
            />
          </Card>
        </Col>
      </Row>

      {/* Activity and Quick Actions */}
      <Row gutter={[24, 24]} style={{ marginTop: 24 }}>
        <Col xs={24} lg={12}>
          <Card 
            title="Recent Activity" 
            extra={<Button type="link">View All</Button>}
            bodyStyle={{ padding: '12px 24px' }}
          >
            <Timeline>
              <Timeline.Item color="green" dot={<CheckCircleOutlined />}>
                <Text strong>New quiz submission</Text>
                <br />
                <Text type="secondary">Advanced English - John Doe</Text>
                <br />
                <Text type="secondary" style={{ fontSize: 12 }}>2 minutes ago</Text>
              </Timeline.Item>
              <Timeline.Item color="blue" dot={<UploadOutlined />}>
                <Text strong>Course material uploaded</Text>
                <br />
                <Text type="secondary">Japanese 101 - Chapter 5</Text>
                <br />
                <Text type="secondary" style={{ fontSize: 12 }}>1 hour ago</Text>
              </Timeline.Item>
              <Timeline.Item color="orange" dot={<ClockCircleOutlined />}>
                <Text strong>Homework deadline reminder</Text>
                <br />
                <Text type="secondary">Business Communication - Essay Due</Text>
                <br />
                <Text type="secondary" style={{ fontSize: 12 }}>3 hours ago</Text>
              </Timeline.Item>
              <Timeline.Item dot={<UserAddOutlined />}>
                <Text strong>New student enrolled</Text>
                <br />
                <Text type="secondary">Web Development Course</Text>
                <br />
                <Text type="secondary" style={{ fontSize: 12 }}>5 hours ago</Text>
              </Timeline.Item>
            </Timeline>
          </Card>
        </Col>
        
        <Col xs={24} lg={12}>
          <Card title="Quick Actions">
            <Row gutter={[16, 16]}>
              <Col span={12}>
                <Button 
                  type="primary" 
                  icon={<PlusOutlined />} 
                  block 
                  size="large"
                  onClick={() => setActiveKey('courses')}
                  style={{ height: 60 }}
                >
                  Create Course
                </Button>
              </Col>
              <Col span={12}>
                <Button 
                  icon={<UploadOutlined />} 
                  block 
                  size="large"
                  onClick={() => setActiveKey('materials')}
                  style={{ height: 60 }}
                >
                  Upload Material
                </Button>
              </Col>
              <Col span={12}>
                <Button 
                  icon={<FormOutlined />} 
                  block 
                  size="large"
                  onClick={() => setActiveKey('quizzes')}
                  style={{ height: 60 }}
                >
                  Create Quiz
                </Button>
              </Col>
              <Col span={12}>
                <Button 
                  icon={<FileTextOutlined />} 
                  block 
                  size="large"
                  onClick={() => setActiveKey('homework')}
                  style={{ height: 60 }}
                >
                  Assign Homework
                </Button>
              </Col>
            </Row>
            
            <Divider />
            
            <Space direction="vertical" style={{ width: '100%' }}>
              <Alert
                message="3 new applications pending review"
                type="info"
                showIcon
                action={
                  <Button size="small" type="primary" onClick={() => setActiveKey('applications')}>
                    Review Now
                  </Button>
                }
              />
            </Space>
          </Card>
        </Col>
      </Row>

      {/* Top Performers */}
      <Row gutter={[24, 24]} style={{ marginTop: 24 }}>
        <Col span={24}>
          <Card 
            title="Top Performing Students" 
            extra={
              <Space>
                <Select defaultValue="all" style={{ width: 120 }}>
                  <Option value="all">All Courses</Option>
                  <Option value="english">English</Option>
                  <Option value="japanese">Japanese</Option>
                </Select>
                <Button type="primary" icon={<TrophyOutlined />}>Award Badges</Button>
              </Space>
            }
          >
            <Table
              dataSource={[
                {
                  key: '1',
                  rank: 1,
                  name: 'Alice Johnson',
                  course: 'Advanced English',
                  score: 95,
                  progress: 98,
                  badges: 5
                },
                {
                  key: '2',
                  rank: 2,
                  name: 'Bob Smith',
                  course: 'Japanese N2',
                  score: 92,
                  progress: 95,
                  badges: 4
                },
                {
                  key: '3',
                  rank: 3,
                  name: 'Carol White',
                  course: 'Business Communication',
                  score: 90,
                  progress: 93,
                  badges: 3
                }
              ]}
              columns={[
                {
                  title: 'Rank',
                  dataIndex: 'rank',
                  key: 'rank',
                  width: 80,
                  render: (rank) => (
                    <Tag color={rank === 1 ? 'gold' : rank === 2 ? 'silver' : 'bronze'}>
                      #{rank}
                    </Tag>
                  )
                },
                {
                  title: 'Student',
                  dataIndex: 'name',
                  key: 'name',
                  render: (name) => (
                    <Space>
                      <Avatar style={{ backgroundColor: '#1890ff' }}>
                        {name.charAt(0)}
                      </Avatar>
                      <Text strong>{name}</Text>
                    </Space>
                  )
                },
                {
                  title: 'Course',
                  dataIndex: 'course',
                  key: 'course',
                  render: (course) => <Tag color="blue">{course}</Tag>
                },
                {
                  title: 'Average Score',
                  dataIndex: 'score',
                  key: 'score',
                  render: (score) => (
                    <Progress 
                      percent={score} 
                      size="small"
                      strokeColor={score >= 90 ? '#52c41a' : score >= 80 ? '#1890ff' : '#faad14'}
                    />
                  )
                },
                {
                  title: 'Course Progress',
                  dataIndex: 'progress',
                  key: 'progress',
                  render: (progress) => `${progress}%`
                },
                {
                  title: 'Badges',
                  dataIndex: 'badges',
                  key: 'badges',
                  render: (badges) => (
                    <Space>
                      {[...Array(badges)].map((_, i) => (
                        <TrophyOutlined key={i} style={{ color: '#faad14' }} />
                      ))}
                    </Space>
                  )
                },
                {
                  title: 'Action',
                  key: 'action',
                  render: () => (
                    <Space>
                      <Button type="link" icon={<EyeOutlined />}>View</Button>
                      <Button type="link" icon={<MessageOutlined />}>Message</Button>
                    </Space>
                  )
                }
              ]}
              pagination={false}
            />
          </Card>
        </Col>
      </Row>
    </div>
  );

  // Simplified component renders (you can expand these as needed)
  const renderCourseManagement = () => (
    <Card title="Course Management" extra={<Button type="primary" icon={<PlusOutlined />}>Create Course</Button>}>
      <Table
        dataSource={courses}
        columns={[
          { title: 'Course Code', dataIndex: 'code', key: 'code' },
          { title: 'Title', dataIndex: 'title', key: 'title' },
          { title: 'Category', dataIndex: 'category', key: 'category' },
          { title: 'Students', dataIndex: 'students', key: 'students', render: (s) => s?.length || 0 },
          { 
            title: 'Actions', 
            key: 'actions',
            render: () => (
              <Space>
                <Button icon={<EditOutlined />} size="small" />
                <Button icon={<DeleteOutlined />} size="small" danger />
              </Space>
            )
          }
        ]}
      />
    </Card>
  );

  const renderMaterialManagement = () => (
    <Card title="Course Materials" extra={<Button type="primary" icon={<UploadOutlined />}>Upload Material</Button>}>
      <Empty description="No materials uploaded yet" />
    </Card>
  );

  const renderQuizManagement = () => (
    <Card title="Quiz Engine" extra={<Button type="primary" icon={<PlusOutlined />}>Create Quiz</Button>}>
      <Empty description="No quizzes created yet" />
    </Card>
  );

  const renderHomeworkManagement = () => (
    <Card title="Homework System" extra={<Button type="primary" icon={<PlusOutlined />}>Assign Homework</Button>}>
      <Empty description="No homework assigned yet" />
    </Card>
  );

  const renderListeningExercises = () => (
    <Card title="Listening Exercises" extra={<Button type="primary" icon={<AudioOutlined />}>Add Exercise</Button>}>
      <Empty description="No listening exercises added yet" />
    </Card>
  );

  const renderStudentProgress = () => (
    <Card title="Student Progress">
      <Table
        dataSource={students}
        columns={[
          { title: 'Name', key: 'name', render: (r) => `${r.firstName} ${r.lastName}` },
          { title: 'Email', dataIndex: 'email', key: 'email' },
          { title: 'Progress', key: 'progress', render: () => <Progress percent={Math.floor(Math.random() * 100)} /> },
          { title: 'Actions', key: 'actions', render: () => <Button icon={<EyeOutlined />} size="small">View</Button> }
        ]}
      />
    </Card>
  );

  const renderApplications = () => (
    <Card title="Applications & Messages">
      <Tabs defaultActiveKey="applications">
        <TabPane tab="Applications" key="applications">
          <Table
            dataSource={applications}
            columns={[
              { title: 'Name', dataIndex: 'fullName', key: 'fullName' },
              { title: 'Email', dataIndex: 'email', key: 'email' },
              { title: 'Status', dataIndex: 'status', key: 'status', render: (s) => <Tag>{s}</Tag> },
              { title: 'Date', dataIndex: 'createdAt', key: 'createdAt', render: (d) => moment(d).format('MMM DD, YYYY') }
            ]}
          />
        </TabPane>
        <TabPane tab="Messages" key="messages">
          <Empty description="No messages" />
        </TabPane>
      </Tabs>
    </Card>
  );

  const renderAnalytics = () => (
    <Card title="Analytics & Reports">
      <Row gutter={[24, 24]}>
        <Col span={12}>
          <Card title="Performance Chart">
            <Bar
              data={{
                labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
                datasets: [{
                  label: 'Average Score',
                  data: [75, 80, 78, 85, 82, 88],
                  backgroundColor: '#1890ff'
                }]
              }}
              options={{
                responsive: true,
                plugins: {
                  legend: { display: false }
                }
              }}
            />
          </Card>
        </Col>
        <Col span={12}>
          <Card title="Student Distribution">
            <Pie
              data={{
                labels: ['Excellent', 'Good', 'Average', 'Below Average'],
                datasets: [{
                  data: [25, 40, 25, 10],
                  backgroundColor: ['#52c41a', '#1890ff', '#faad14', '#f5222d']
                }]
              }}
              options={{
                responsive: true,
                plugins: {
                  legend: { position: 'bottom' }
                }
              }}
            />
          </Card>
        </Col>
      </Row>
    </Card>
  );

  const renderSettings = () => (
    <Card title="Settings">
      <Tabs defaultActiveKey="profile">
        <TabPane tab="Profile" key="profile">
          <Form layout="vertical">
            <Row gutter={16}>
              <Col span={12}>
                <Form.Item label="First Name">
                  <Input defaultValue={currentUser?.firstName} />
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item label="Last Name">
                  <Input defaultValue={currentUser?.lastName} />
                </Form.Item>
              </Col>
            </Row>
            <Form.Item label="Email">
              <Input defaultValue={currentUser?.email} disabled />
            </Form.Item>
            <Form.Item label="Role">
              <Input defaultValue={currentUser?.role} disabled />
            </Form.Item>
            <Button type="primary">Update Profile</Button>
          </Form>
        </TabPane>
        <TabPane tab="Preferences" key="preferences">
          <Form layout="vertical">
            <Form.Item label="Language">
              <Select defaultValue="en">
                <Option value="en">English</Option>
                <Option value="ja">Japanese</Option>
              </Select>
            </Form.Item>
            <Form.Item label="Theme">
              <Radio.Group value={theme} onChange={(e) => setTheme(e.target.value)}>
                <Radio value="light">Light</Radio>
                <Radio value="dark">Dark</Radio>
              </Radio.Group>
            </Form.Item>
            <Form.Item label="Email Notifications">
              <Switch defaultChecked />
            </Form.Item>
            <Button type="primary">Save Preferences</Button>
          </Form>
        </TabPane>
        <TabPane tab="Security" key="security">
          <Form layout="vertical">
            <Form.Item label="Current Password">
              <Input.Password />
            </Form.Item>
            <Form.Item label="New Password">
              <Input.Password />
            </Form.Item>
            <Form.Item label="Confirm Password">
              <Input.Password />
            </Form.Item>
            <Button type="primary">Change Password</Button>
          </Form>
        </TabPane>
      </Tabs>
    </Card>
  );

  // Main content renderer
  const renderContent = () => {
    switch(activeKey) {
      case 'overview':
        return renderOverview();
      case 'courses':
        return renderCourseManagement();
      case 'materials':
        return renderMaterialManagement();
      case 'quizzes':
        return renderQuizManagement();
      case 'homework':
        return renderHomeworkManagement();
      case 'listening':
        return renderListeningExercises();
      case 'students':
        return renderStudentProgress();
      case 'applications':
        return renderApplications();
      case 'analytics':
        return renderAnalytics();
      case 'settings':
        return renderSettings();
      default:
        return renderOverview();
    }
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '100vh',
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'
      }}>
        <Spin size="large" tip="Loading Dashboard..." />
      </div>
    );
  }

  return (
    <Layout style={{ minHeight: '100vh' }}>
      {/* Modern Sidebar */}
      <Sider 
        trigger={null} 
        collapsible 
        collapsed={collapsed}
        breakpoint="lg"
        onBreakpoint={(broken) => {
          setCollapsed(broken);
        }}
        width={260}
        className="modern-sidebar"
        style={{
          background: 'linear-gradient(180deg, #667eea 0%, #764ba2 50%, #f093fb 100%)',
          position: 'fixed',
          height: '100vh',
          left: 0,
          top: 0,
          bottom: 0,
          zIndex: 1000,
          boxShadow: '4px 0 30px rgba(102, 126, 234, 0.4)',
          overflow: 'auto'
        }}
      >
        {/* Logo Section */}
        <div className="sidebar-logo-section" style={{
          padding: '30px 20px',
          textAlign: 'center',
          borderBottom: '2px solid rgba(255, 255, 255, 0.2)',
          background: 'rgba(255, 255, 255, 0.1)'
        }}>
          <div className="logo-container">
            <div className="logo-icon-box" style={{
              width: 70,
              height: 70,
              margin: '0 auto',
              background: 'linear-gradient(135deg, #ff6b6b 0%, #ee5a52 100%)',
              borderRadius: 20,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              boxShadow: '0 10px 30px rgba(255, 107, 107, 0.4)',
              marginBottom: 15
            }}>
              <RocketOutlined style={{ fontSize: 35, color: '#fff' }} />
            </div>
            {!collapsed && (
              <div>
                <Title level={3} style={{ color: '#fff', margin: 0 }}>
                  Forum Academy
                </Title>
                <Badge 
                  count="ADMIN PORTAL" 
                  style={{ 
                    backgroundColor: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
                    color: '#fff',
                    marginTop: 8
                  }} 
                />
              </div>
            )}
          </div>
        </div>
        
        {/* Navigation Menu */}
        <Menu
          theme="dark"
          mode="inline"
          selectedKeys={[activeKey]}
          onClick={(e) => setActiveKey(e.key)}
          style={{ 
            background: 'transparent',
            borderRight: 0,
            padding: '20px 10px'
          }}
          items={menuItems.map(item => ({
            ...item,
            style: {
              margin: '8px 0',
              borderRadius: '12px'
            }
          }))}
        />

        {/* Status Section */}
        {!collapsed && (
          <div className="sidebar-status" style={{
            padding: 20,
            borderTop: '1px solid rgba(255, 255, 255, 0.1)'
          }}>
            <div style={{
              background: 'rgba(255, 255, 255, 0.1)',
              padding: 12,
              borderRadius: 10,
              marginBottom: 12
            }}>
              <Text style={{ color: 'rgba(255, 255, 255, 0.7)', fontSize: 11 }}>
                COMPLETION RATE
              </Text>
              <Progress 
                percent={dashboardStats.completionRate || 75} 
                strokeColor="#4facfe"
                trailColor="rgba(255, 255, 255, 0.2)"
                showInfo={false}
              />
            </div>
            <div style={{
              background: 'rgba(255, 255, 255, 0.1)',
              padding: 12,
              borderRadius: 10
            }}>
              <Text style={{ color: 'rgba(255, 255, 255, 0.7)', fontSize: 11 }}>
                ACTIVE USERS
              </Text>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 8 }}>
                <Text style={{ color: '#fff', fontSize: 20, fontWeight: 700 }}>
                  {dashboardStats.totalStudents}
                </Text>
                <TeamOutlined style={{ color: 'rgba(255, 255, 255, 0.8)', fontSize: 18 }} />
              </div>
            </div>
          </div>
        )}

        {/* User Profile Section */}
        <div className="sidebar-user-section" style={{
          padding: 20,
          marginTop: 'auto',
          borderTop: '1px solid rgba(255, 255, 255, 0.2)',
          background: 'rgba(255, 255, 255, 0.05)'
        }}>
          <div 
            style={{
              background: 'rgba(255, 255, 255, 0.2)',
              padding: 12,
              borderRadius: 12,
              display: 'flex',
              alignItems: 'center',
              gap: 12,
              cursor: 'pointer',
              transition: 'all 0.3s'
            }}
            onClick={handleLogout}
          >
            <Avatar 
              style={{ 
                backgroundColor: '#ff6b6b',
                minWidth: 40
              }}
            >
              {currentUser?.firstName?.charAt(0)}
            </Avatar>
            {!collapsed && (
              <>
                <div style={{ flex: 1 }}>
                  <Text style={{ color: '#fff', display: 'block', fontWeight: 700 }}>
                    {currentUser?.firstName} {currentUser?.lastName}
                  </Text>
                  <Text style={{ color: 'rgba(255, 255, 255, 0.6)', fontSize: 12 }}>
                    {currentUser?.role}
                  </Text>
                </div>
                <LogoutOutlined style={{ color: 'rgba(255, 255, 255, 0.6)' }} />
              </>
            )}
          </div>
        </div>
      </Sider>

      {/* Main Layout */}
      <Layout style={{ marginLeft: collapsed ? 80 : 260, transition: 'all 0.3s' }}>
        {/* Header */}
        <Header style={{ 
          padding: '0 24px', 
          background: '#fff',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          position: 'sticky',
          top: 0,
          zIndex: 999
        }}>
          <Space>
            <Button
              type="text"
              icon={collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />}
              onClick={() => setCollapsed(!collapsed)}
              style={{ fontSize: 18 }}
            />
            <Breadcrumb>
              <Breadcrumb.Item>
                <HomeOutlined />
              </Breadcrumb.Item>
              <Breadcrumb.Item>
                {menuItems.find(item => item.key === activeKey)?.label || 'Dashboard'}
              </Breadcrumb.Item>
            </Breadcrumb>
          </Space>

          <Space size="large">
            <Input.Search 
              placeholder="Search..." 
              style={{ width: 300 }}
              prefix={<SearchOutlined />}
            />
            
            <Dropdown
              overlay={
                <Menu>
                  <Menu.Item key="1">New Course</Menu.Item>
                  <Menu.Item key="2">New Quiz</Menu.Item>
                  <Menu.Item key="3">New Assignment</Menu.Item>
                </Menu>
              }
            >
              <Button type="primary" icon={<PlusOutlined />}>
                Quick Add
              </Button>
            </Dropdown>

            <Badge count={5}>
              <Button 
                type="text" 
                icon={<BellOutlined />} 
                style={{ fontSize: 18 }}
              />
            </Badge>

            <Dropdown
              overlay={
                <Menu>
                  <Menu.Item key="profile" onClick={() => setActiveKey('settings')}>
                    <UserOutlined /> Profile
                  </Menu.Item>
                  <Menu.Item key="settings" onClick={() => setActiveKey('settings')}>
                    <SettingOutlined /> Settings
                  </Menu.Item>
                  <Menu.Divider />
                  <Menu.Item key="logout" onClick={handleLogout}>
                    <LogoutOutlined /> Logout
                  </Menu.Item>
                </Menu>
              }
            >
              <Space style={{ cursor: 'pointer' }}>
                <Avatar style={{ backgroundColor: '#1890ff' }}>
                  {currentUser?.firstName?.charAt(0)}
                </Avatar>
                <Text strong>{currentUser?.firstName}</Text>
              </Space>
            </Dropdown>
          </Space>
        </Header>

        {/* Content */}
        <Content style={{ 
          margin: '24px', 
          minHeight: 280,
          background: '#f0f2f5'
        }}>
          {renderContent()}
        </Content>

        {/* Footer */}
        <Layout.Footer style={{ textAlign: 'center', background: '#fff' }}>
          <Text type="secondary">
            Forum Academy Admin Dashboard ©{new Date().getFullYear()} | Powered by React & Ant Design
          </Text>
        </Layout.Footer>
      </Layout>
    </Layout>
  );
};

// Add custom styles
const style = document.createElement('style');
style.innerHTML = `
  .modern-sidebar .ant-menu-item-selected {
    background: linear-gradient(135deg, #ff6b6b 0%, #ee5a52 100%) !important;
  }
  
  .modern-sidebar .ant-menu-item:hover {
    background: rgba(255, 255, 255, 0.2) !important;
  }
  
  .stat-card {
    transition: all 0.3s;
    border: none !important;
  }
  
  .stat-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 30px rgba(0,0,0,0.15);
  }
  
  .gradient-blue {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  }
  
  .gradient-green {
    background: linear-gradient(135deg, #56ab2f 0%, #a8e063 100%);
  }
  
  .gradient-orange {
    background: linear-gradient(135deg, #f2994a 0%, #f2c94c 100%);
  }
  
  .gradient-purple {
    background: linear-gradient(135deg, #8e2de2 0%, #4a00e0 100%);
  }
  
  .ant-layout-sider-collapsed .sidebar-status,
  .ant-layout-sider-collapsed .sidebar-user-section > div > div:last-child {
    display: none;
  }
`;
document.head.appendChild(style);

export default AdminFacultyDashboard;
